import requests
from urllib.parse import urlparse
import ipaddress
from flask import abort

ALLOWED_SCHEMES = {'http', 'https'}

def is_safe_url(url: str) -> bool:
    parsed = urlparse(url)
    if parsed.scheme not in ALLOWED_SCHEMES:
        return False
    try:
        ip = ipaddress.ip_address(parsed.hostname)
        return not (ip.is_private or ip.is_loopback or ip.is_link_local)
    except ValueError:
        return True  # hostname, not IP — additional DNS rebinding protection needed

@app.route('/fetch')
def fetch_url():
    url = request.args.get('url', '')
    if not is_safe_url(url):
        abort(400)
    response = requests.get(url, timeout=5)
    return jsonify({'content': response.text[:1000]})

import urllib.request
from urllib.parse import urlparse
from django.http import HttpResponse, HttpResponseBadRequest

def proxy_image(request):
    image_url = request.GET.get('src', '')
    parsed = urlparse(image_url)
    if parsed.scheme not in ('http', 'https'):
        return HttpResponseBadRequest('Only http/https allowed')
    if parsed.hostname in ('localhost', '127.0.0.1', '::1') or \
       (parsed.hostname or '').startswith('169.254.'):
        return HttpResponseBadRequest('Internal addresses not allowed')
    with urllib.request.urlopen(image_url, timeout=5) as response:
        data = response.read(16 * 1024)  # limit response size
    return HttpResponse(data, content_type='image/jpeg')

