import requests
from urllib.parse import urlparse
import ipaddress

ALLOWED_HEALTH_CHECK_DOMAINS = {'api.example.com', 'service.example.com'}

def check_external_service_health(service_config: dict) -> dict:
    url = service_config['health_check_url']
    parsed = urlparse(url)
    if parsed.hostname not in ALLOWED_HEALTH_CHECK_DOMAINS:
        raise ValueError(f'Health check URL hostname not in allowlist: {parsed.hostname}')
    if parsed.scheme not in ('http', 'https'):
        raise ValueError('Only http/https allowed for health checks')
    resp = requests.get(url, timeout=3)
    return {'healthy': resp.status_code == 200}

