import requests
from urllib.parse import urlparse
import ipaddress

def _is_safe_external_url(url: str) -> bool:
    parsed = urlparse(url)
    if parsed.scheme not in ('http', 'https'):
        return False
    host = parsed.hostname or ''
    BLOCKED = {'169.254.169.254', 'metadata.google.internal'}
    if host in BLOCKED:
        return False
    try:
        ip = ipaddress.ip_address(host)
        return not (ip.is_private or ip.is_loopback or ip.is_link_local)
    except ValueError:
        return True

def upload_from_url(s3_bucket: str, s3_key: str, source_url: str) -> bool:
    if not _is_safe_external_url(source_url):
        raise ValueError(f'Unsafe source URL: {source_url}')
    response = requests.get(source_url, stream=True, timeout=30)
    s3 = boto3.client('s3')
    s3.upload_fileobj(response.raw, s3_bucket, s3_key)
    return True

import requests
from urllib.parse import urlparse
import ipaddress
import socket

def fetch_avatar(avatar_url: str) -> bytes:
    parsed = urlparse(avatar_url)
    if parsed.scheme not in ('http', 'https'):
        raise ValueError('Only http/https allowed')
    hostname = parsed.hostname or ''
    try:
        ip = ipaddress.ip_address(hostname)
        if ip.is_private or ip.is_loopback or ip.is_link_local:
            raise ValueError('Internal IP address not allowed')
    except ValueError as e:
        if 'not allowed' in str(e):
            raise
        # Resolve hostname and check resolved IP
        resolved = socket.gethostbyname(hostname)
        resolved_ip = ipaddress.ip_address(resolved)
        if resolved_ip.is_private or resolved_ip.is_loopback:
            raise ValueError(f'Hostname {hostname!r} resolves to internal IP')
    response = requests.get(avatar_url, timeout=5)
    return response.content[:1024 * 1024]  # 1MB limit

