import requests
from urllib.parse import urlparse
import ipaddress

ALLOWED_WEBHOOK_SCHEMES = {'https'}  # Require HTTPS for webhooks

def validate_webhook_url(url: str) -> None:
    parsed = urlparse(url)
    if parsed.scheme not in ALLOWED_WEBHOOK_SCHEMES:
        raise ValueError(f'Webhook URL must use HTTPS, got: {parsed.scheme}')
    host = parsed.hostname or ''
    try:
        ip = ipaddress.ip_address(host)
        if ip.is_private or ip.is_loopback or ip.is_link_local:
            raise ValueError(f'Internal IP not allowed: {host}')
    except ValueError as e:
        if 'not allowed' in str(e):
            raise

class WebhookNotifier:
    def __init__(self, webhook_urls: list[str]):
        for url in webhook_urls:
            validate_webhook_url(url)
        self.webhook_urls = webhook_urls

    def notify(self, event_data: dict) -> list[dict]:
        results = []
        for url in self.webhook_urls:
            try:
                resp = requests.post(url, json=event_data, timeout=10)
                results.append({'url': url, 'status': resp.status_code})
            except Exception as e:
                results.append({'url': url, 'error': str(e)})
        return results
